func TestParse_Success(t *testing.T) {
	raw := []byte(`{"jsonrpc":"2.0","id":1,"result":{"tools":[]}}`)
	result, err := parse(raw, 1)
	if err != nil {
		t.Fatalf("parse: %v", err)
	}
	if result == nil {
		t.Fatal("result is nil")
	}

	var data map[string]any
	json.Unmarshal(result, &data)
	if _, ok := data["tools"]; !ok {
		t.Error("expected tools in result")
	}
}

func TestParse_RPCError(t *testing.T) {
	raw := []byte(`{"jsonrpc":"2.0","id":1,"error":{"code":-32600,"message":"Invalid Request"}}`)
	_, err := parse(raw, 1)
	if err == nil {
		t.Fatal("expected error")
	}
	if !strings.Contains(err.Error(), "Invalid Request") {
		t.Errorf("err = %v", err)
	}
}

