func TestParseSSE_Basic(t *testing.T) {
	sse := "data: {\"jsonrpc\":\"2.0\",\"id\":1,\"result\":{\"key\":\"value\"}}\n\n"
	result, err := parseSSE(strings.NewReader(sse), 1)
	if err != nil {
		t.Fatalf("parseSSE: %v", err)
	}

	var data map[string]any
	json.Unmarshal(result, &data)
	if data["key"] != "value" {
		t.Errorf("result = %v", data)
	}
}

